405: func (r *raftNode) stop() {
406: 	select {
407: 	case r.stopped <- struct{}{}:
408: 		// Not already stopped, so trigger it
409: 	case <-r.done:
410: 		// Has already been stopped - no need to do anything
411: 		return
412: 	}
413: 	// Block until the stop has been acknowledged by start()
414: 	<-r.done
415: }
