417: func (r *raftNode) onStop() {
418: 	r.Stop()
419: 	r.ticker.Stop()
420: 	r.transport.Stop()
421: 	if err := r.storage.Close(); err != nil {
422: 		r.lg.Panic("failed to close Raft storage", zap.Error(err))
423: 	}
424: 	close(r.done)
425: }
